function.body:
v_Display VARCHAR2(200):='';
  v_sql VARCHAR2(2000):='';
BEGIN

  v_sql:=  'SELECT c_costcenter_id FROM c_costcenter WHERE c_costcenter_id = (
    SELECT c_costcenter_id FROM ' || p_tablename || '  WHERE documentno = ''' || documentno || ''');';


  EXECUTE IMMEDIATE v_sql INTO v_Display;
  RETURN v_Display;
EXCEPTION
WHEN OTHERS THEN
  RETURN '';
END SACGLD_COSTCENTER
